window.photoOf = function(roomId, a, b){
  try{
    if(b!==undefined && b!==null){ return window.PLAYER_PHOTOS[roomId+"|"+a+"|"+b]||null; }
    // compat antigo: photoOf(roomId, pid) -> procura qualquer time
    var pid=a; var pre=roomId+"|";
    for(var k in window.PLAYER_PHOTOS){ if(k.indexOf(pre)===0 && k.slice(k.lastIndexOf("|")+1)===String(pid)) return window.PLAYER_PHOTOS[k]; }
    return null;
  }catch(e){ return null; }
};